          <Button size="icon-sm" variant="ghost">
            <MailIcon />
          </Button>
          <Button size="icon-sm" variant="ghost" className="relative">
            <BellIcon />
            <Badge className="absolute -top-2 left-full min-w-5 -translate-x-1/2 px-1 text-[10px]">
              5
            </Badge>
